/**
 * Printables data — THE FRONT DOOR (WEBSITE-BUILD-SPEC §2; taxonomy LOCKED, 7 categories).
 *
 * Single source of truth for the printables grid. The per-sheet entries in `printables.json` are
 * GENERATED by the mascotAI renderer (`scripts/render_printables.py` in the mascotAI repo): every
 * PDF + thumbnail under `public/printables/<category>/` is produced by the real deterministic
 * generators at 300 DPI, and the script writes the JSON manifest consumed here. To add or change a
 * printable, re-run that script — do NOT hand-edit `printables.json` (it will be overwritten).
 *
 * The category METADATA (titles, SEO copy, icons) lives here — it is site presentation, not
 * generated content.
 *
 * ── EMAIL-GATE TODO (commission 037) ──────────────────────────────────────────────────────────
 * The newsletter/email capture is 037-gated and NOT live (see src/config/funnel.ts —
 * `newsletterLive === false` until the sending domain is authenticated). So EVERY printable here,
 * including the teacher-pack magnet, ships as a FREE UNGATED download today — an ungated free
 * download beats an empty "coming soon" shell or a broken email wall. When 037 lands and
 * `newsletterLive` flips true, the teacher pack (`EMAIL_MAGNET_SLUG` below) should gain its email
 * gate: swap its direct PDF link for an inline signup that reveals the download on submit. The hook
 * is `isEmailMagnet(item)` + the `newsletterLive` flag; wire the gate there, and do NOT gate any
 * other sheet. Until then the teacher pack is a normal free download.
 */

import manifest from './printables.json'

export type CategoryId =
  | 'coloring'
  | 'crafts'
  | 'puzzles'
  | 'activities'
  | 'music'
  | 'teaching-guides'
  | 'make-your-own'

export interface Printable {
  category: CategoryId
  slug: string
  title: string
  alt: string
  ageBand: string
  blurb: string
  pdf: string
  thumb: string
  thumbWidth: number
  thumbHeight: number
  featured: boolean
  downloadEvent: string
}

export const printables: Printable[] = manifest as Printable[]

/** The slug of the teacher-pack email magnet — the ONE sheet that gains an email gate at 037. */
export const EMAIL_MAGNET_SLUG = 'butterfly-teacher-pack-book-one'

export function isEmailMagnet(item: Printable): boolean {
  return item.slug === EMAIL_MAGNET_SLUG
}

export interface CategoryMeta {
  id: CategoryId
  /** Short label for the landing-grid card + nav. */
  navTitle: string
  /** Lucide icon name (matches the index category cards). */
  icon: string
  /** One-line teaser on the landing grid. */
  teaser: string
  /** <h1> on the category page. */
  pageTitle: string
  /** Landing subtitle under the <h1>. */
  subtitle: string
  /** <title> tag (SEO). */
  seoTitle: string
  /** Meta description (SEO). */
  seoDescription: string
}

