export function printablesByCategory(category: CategoryId): Printable[] {
  return printables.filter((p) => p.category === category)
}

export function categoryCount(category: CategoryId): number {
  return printablesByCategory(category).length
}

export function featuredPrintables(): Printable[] {
  return printables.filter((p) => p.featured)
}

export const totalPrintables = printables.length
